SELECT r.id AS roomId, r.room_name AS roomName, r.creator_id AS creatorId, r.room_status AS roomStatus, r.max_users AS maxUsers, r.create_time AS createTime, r.close_time AS closeTime, u.username AS creatorNickname, u.user_avatar AS creatorAvatar FROM tb_music_room r LEFT JOIN tb_user u ON r.creator_id = u.id WHERE r.id IN
#{id}
ORDER BY r.create_time DESC
